  /**
 * Carica le spese disattivate (eliminate) per un mese specifico
 */
  async loadDeletedExpensesForMonth(month: string): Promise<Expense[]> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return [];

      const formattedMonth = this.formatMonthForDatabase(month);
      console.log('🗑️ Loading deleted expenses for month:', formattedMonth);

      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .select('*')
        .eq('restaurant_id', restaurantId)
        .eq('month', formattedMonth)
        .not('deleted_at', 'is', null) // Solo spese eliminate (soft delete)
        .order('deleted_at', { ascending: false })
        .order('type', { ascending: true });

      if (error) throw error;

      console.log('✅ Deleted expenses loaded:', data?.length || 0);
      return data || [];
    } catch (error) {
      console.error('❌ Error loading deleted expenses:', error);
      return [];
    }
  }

  /**
   * Carica tutte le spese disattivate per intervallo date
   */
  async loadDeletedExpensesForDateRange(startMonth: string, endMonth: string): Promise<Expense[]> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return [];

      const formattedStart = this.formatMonthForDatabase(startMonth);
      const formattedEnd = this.formatMonthForDatabase(endMonth);

      console.log('🗑️ Loading deleted expenses for date range:', { formattedStart, formattedEnd });

      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .select('*')
        .eq('restaurant_id', restaurantId)
        .gte('month', formattedStart)
        .lte('month', formattedEnd)
        .not('deleted_at', 'is', null) // Solo spese eliminate
        .order('deleted_at', { ascending: false })
        .order('month', { ascending: false });

      if (error) throw error;

      return data || [];
    } catch (error) {
      console.error('❌ Error loading deleted expenses for date range:', error);
      return [];
    }
  }

  async hardDelete(id: string): Promise<boolean> {
  try {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return false;

    const { error } = await this.supabaseService.getSupabaseClient()
      .from(this.getTableName())
      .delete()
      .eq('id', id)
      .eq('restaurant_id', restaurantId);

    if (error) throw error;
    return true;
  } catch (error) {
    console.error('❌ Error hard deleting expense:', error);
    return false;
  }
}

